var N=20,N_MIN=16;
var G_CRIT={3:1.155,4:1.481,5:1.715,6:1.887,7:2.020,8:2.126,9:2.215,10:2.290,11:2.355,12:2.412,13:2.462,14:2.507,15:2.549,16:2.585,17:2.620,18:2.651,19:2.681,20:2.709,25:2.822,30:2.908};
function gcrit(n){if(G_CRIT[n])return G_CRIT[n];var k=Object.keys(G_CRIT).map(Number).sort(function(a,b){return a-b;});for(var i=0;i<k.length-1;i++){if(n>=k[i]&&n<=k[i+1]){var t=(n-k[i])/(k[i+1]-k[i]);return G_CRIT[k[i]]+t*(G_CRIT[k[i+1]]-G_CRIT[k[i]]);}}return G_CRIT[20];}
function grubbs(win,val){var n=win.length;if(n<N_MIN)return false;var mean=win.reduce(function(a,b){return a+b;},0)/n;var std=Math.sqrt(win.reduce(function(a,b){return a+Math.pow(b-mean,2);},0)/(n-1));if(std<1e-10)return false;return(Math.abs(val-mean)/std)>gcrit(n);}
var nodeId=msg.topic.split('/')[1];
var d=msg.payload;
var key='grubbs_'+nodeId;
var st=flow.get(key)||{P:{win:[],faults:0},T:{win:[],faults:0},RH:{win:[],faults:0}};
var anyFault=false;
var result={};
['P','T','RH'].forEach(function(p){var s=st[p],v=d[p];if(typeof v!=='number'||isNaN(v)){result[p]={outlier:true};s.faults++;anyFault=true;return;}if(grubbs(s.win,v)){result[p]={outlier:true};s.faults++;anyFault=true;}else{s.win.push(v);if(s.win.length>N)s.win.shift();result[p]={outlier:false,value:v};}});
flow.set(key,st);
function mk(p){var r=result[p];if(r.outlier)return null;return{topic:anyFault?nodeId+'-c':nodeId,payload:r.value,_nodeId:nodeId};}
return[mk('P'),mk('T'),mk('RH'),{payload:{nodeId:nodeId,P:st.P.faults,T:st.T.faults,RH:st.RH.faults}}];

var STALE_MS=300000,N_CONF_MIN=16,WIN=60,TREND_WIN=30,TREND_THRESH=0.003;
var nodeId=msg._nodeId||msg.topic.replace(/-c$/,'');
var latest=flow.get('p_latest')||{};
latest[nodeId]={v:msg.payload,t:Date.now()};
flow.set('p_latest',latest);
var nodes=['bills-office','mud-room','garage'];
if(!nodes.every(function(n){return latest[n];}))return null;
var stats=flow.get('p_diff_stats')||{'BO-MR':{win:[],mean:0,std:0},'BO-GA':{win:[],mean:0,std:0},'MR-GA':{win:[],mean:0,std:0}};
var pairs={'BO-MR':latest['bills-office'].v-latest['mud-room'].v,'BO-GA':latest['bills-office'].v-latest['garage'].v,'MR-GA':latest['mud-room'].v-latest['garage'].v};
Object.keys(pairs).forEach(function(k){var d=pairs[k],s=stats[k];s.win.push(d);if(s.win.length>WIN)s.win.shift();var n=s.win.length;s.mean=s.win.reduce(function(a,b){return a+b;},0)/n;s.std=n>1?Math.sqrt(s.win.reduce(function(a,b){return a+Math.pow(b-s.mean,2);},0)/(n-1)):0;});
flow.set('p_diff_stats',stats);
var now=Date.now();
var primary=null,primaryNode=null;
for(var i=0;i<nodes.length;i++){var e=latest[nodes[i]];if(e&&(now-e.t)<STALE_MS){primary=e.v;primaryNode=nodes[i];break;}}
if(primary===null)return null;
var tb=flow.get('p_trend_buf')||[];
tb.push({v:primary,t:now});if(tb.length>TREND_WIN)tb.shift();
flow.set('p_trend_buf',tb);
var trendStr='→ stable';
if(tb.length>=2){var dt=(tb[tb.length-1].t-tb[0].t)/3600000;var dv=tb[tb.length-1].v-tb[0].v;var rate=dt>0?dv/dt:0;if(rate>TREND_THRESH)trendStr='↑ +'+rate.toFixed(3)+' PSI/hr';else if(rate<-TREND_THRESH)trendStr='↓ '+rate.toFixed(3)+' PSI/hr';}
var minN=Math.min.apply(null,Object.keys(stats).map(function(k){return stats[k].win.length;}));
var confStr='calibrating (N='+minN+'/16)';
if(minN>=N_CONF_MIN){var maxStd=Math.max.apply(null,Object.keys(stats).map(function(k){return stats[k].std;}));var pct=(3*maxStd/primary)*100;confStr='± '+pct.toFixed(2)+'%';}
msg.payload={pressure:primary.toFixed(3),source:primaryNode,trend:trendStr,conf:confStr};
return msg;

var d=msg.payload;
var counts=flow.get('fault_counts')||{};
['bills-office','mud-room','garage'].forEach(function(n){if(!counts[n])counts[n]={P:0,T:0,RH:0};});
counts[d.nodeId]={P:d.P,T:d.T,RH:d.RH};
flow.set('fault_counts',counts);
msg.payload=counts;
return msg;

var icon = msg.payload.state === 'open' ? 'ὑ3 OPEN' : 'ὑ2 closed';
msg.topic = msg.payload.device;
msg.payload = icon + '  (' + msg.topic + ')';
return msg;

var icon = msg.payload.state === 'detected' ? 'Ὢ8 DETECTED' : '✅ clear';
msg.topic = msg.payload.device;
msg.payload = icon + '  (' + msg.topic + ')';
return msg;

msg.topic = msg.payload.device;
msg.payload = msg.payload.smoke;
return msg;

if (msg.payload.alert === true) {
    msg.payload = 'Ὢ8 ALARM: ' + msg.payload.type.toUpperCase() + ' — node: ' + msg.payload.device;
    return msg;
}
return null;

var trig = msg.payload.trigger === 'button' ? 'ὑ4 Doorbell' : '὆4 Motion';
var ts = new Date().toLocaleTimeString();
msg.payload = trig + '  @ ' + ts;
return msg;

var nodeId = msg.topic.split('/')[1];
var ls = flow.get('node_lastseen') || {};
ls[nodeId] = Date.now();
flow.set('node_lastseen', ls);
return null;

var STALE_MS = 300000;
var nodes = ['bills-office','mud-room','garage'];
var labels = {'bills-office':'Bills Office','mud-room':'Mud Room','garage':'Garage'};
var ls = flow.get('node_lastseen') || {};
var now = Date.now();
var rows = nodes.map(function(n) {
    var t = ls[n];
    if (!t) return {node: labels[n], age: 'never', ok: false};
    var age = Math.floor((now - t) / 1000);
    return {node: labels[n], age: age + 's ago', ok: age < (STALE_MS/1000)};
});
msg.payload = rows;
return msg;

var nodes = ['bills-office','mud-room','garage'];
var counts = flow.get('fault_counts') || {};
nodes.forEach(function(n){ if(!counts[n]) counts[n]={P:0,T:0,RH:0}; });
if (msg.payload === 'ALL') {
    nodes.forEach(function(n) { flow.set('grubbs_' + n, null); counts[n]={P:0,T:0,RH:0}; });
    flow.set('p_latest', null);
    flow.set('p_diff_stats', null);
    flow.set('p_trend_buf', null);
    node.warn('Grubbs reset: ALL nodes');
} else {
    flow.set('grubbs_' + msg.payload, null);
    counts[msg.payload] = {P:0, T:0, RH:0};
    node.warn('Grubbs reset: ' + msg.payload);
}
flow.set('fault_counts', counts);
return null;

var b64 = msg.payload.toString("base64");
var imgMsg = {payload: b64};
var respMsg = {payload: "OK", statusCode: 200, req: msg.req, res: msg.res};
return [imgMsg, respMsg];

msg.payload = JSON.stringify({"msg":{"cmd":"scan","data":{"account_topic":"reserve"}}});
msg.ip   = "239.255.255.250";
msg.port = 4001;
return msg;

try {
    var d = JSON.parse(msg.payload);
    if (!d.msg) return null;

    if (d.msg.cmd === 'scan') {
        var info = d.msg.data;
        var devs = flow.get('govee_devices') || {};
        devs[info.device] = { ip: info.ip, sku: info.sku, device: info.device };
        flow.set('govee_devices', devs);
        node.status({fill:'green', shape:'dot', text: info.sku + ' @ ' + info.ip});
        msg.payload = devs;
        return [msg, null];
    }

    if (d.msg.cmd === 'devStatus') {
        var nameMap  = flow.get('govee_names')   || {};
        var devs2    = flow.get('govee_devices')  || {};
        var idToName = {};
        Object.keys(nameMap).forEach(function(n) { idToName[nameMap[n]] = n; });
        var dev = Object.values(devs2).find(function(x) { return x.ip === msg.ip; });
        var label = dev ? (idToName[dev.device] || dev.device) : msg.ip;

        var snapshot = flow.get('govee_snapshot') || {};
        snapshot[label] = d.msg.data;
        flow.set('govee_snapshot', snapshot);
        var count = Object.keys(snapshot).length;
        node.status({fill:'blue', shape:'dot', text: 'status ' + count + '/4'});
        if (count >= 4) {
            node.status({fill:'green', shape:'ring', text: 'snapshot ready'});
            msg.payload = snapshot;
            return [null, msg];
        }
        return null;
    }

    return null;
} catch(e) {
    node.warn('parse error: ' + e.message);
    return null;
}

// Expects: msg.govee_cmd     = {cmd:'...', data:{...}}
//          msg.govee_targets = 'all' | ['name-or-device-id', ...]
var devs     = flow.get('govee_devices') || {};
var nameMap  = flow.get('govee_names')   || {};
if (!Object.keys(devs).length) { node.warn('No Govee devices found - run discovery first'); return null; }

var targets;
if (!msg.govee_targets || msg.govee_targets === 'all') {
    targets = Object.values(devs);
} else {
    var ids = Array.isArray(msg.govee_targets) ? msg.govee_targets : [msg.govee_targets];
    ids = ids.map(function(t) { return nameMap[t] || t; });
    targets = ids.map(function(id) { return devs[id]; }).filter(Boolean);
}
if (!targets.length) { node.warn('No matching Govee devices'); return null; }

var msgs = targets.map(function(d) {
    return { payload: JSON.stringify({msg: msg.govee_cmd}), ip: d.ip, port: 4003 };
});
return [msgs];

node.warn('SRC:mqtt-ctrl retain=' + msg.retain + ' payload=' + JSON.stringify(msg.payload));
if (msg.retain) return null;
// MQTT payload: {cmd, value|r,g,b|kelvin, devices:'all'|[ids]}
var p = msg.payload;
var gcmd;
switch (p.cmd) {
    case 'turn':       gcmd = {cmd:'turn',       data:{value: p.value ? 1 : 0}}; break;
    case 'brightness': gcmd = {cmd:'brightness',  data:{value: p.value}}; break;
    case 'color':      gcmd = {cmd:'colorwc',     data:{color:{r:p.r||0,g:p.g||0,b:p.b||0}, colorTemInKelvin:0}}; break;
    case 'colortemp':  gcmd = {cmd:'colorwc',     data:{color:{r:0,g:0,b:0}, colorTemInKelvin:p.kelvin||4000}}; break;
    default: node.warn('Unknown Govee cmd: ' + p.cmd); return null;
}
msg.govee_cmd     = gcmd;
msg.govee_targets = p.devices || 'all';
return msg;

node.warn('SRC:visitor retain=' + msg.retain);
if (msg.retain) return null;
// Doorbell / motion at front door → warm white
msg.govee_cmd     = {cmd:'colorwc', data:{color:{r:0,g:0,b:0}, colorTemInKelvin:3000}};
msg.govee_targets = 'all';
return msg;

node.warn('SRC:alarm retain=' + msg.retain);
if (msg.retain) return null;
// Smoke / CO alert → solid red; clear → restore warm white
if (!msg.payload) return null;
if (msg.payload.alert === true) {
    msg.govee_cmd = {cmd:'colorwc', data:{color:{r:255,g:0,b:0}, colorTemInKelvin:0}};
} else {
    msg.govee_cmd = {cmd:'colorwc', data:{color:{r:0,g:0,b:0}, colorTemInKelvin:3000}};
}
msg.govee_targets = 'all';
return msg;

var topics = [
    'home/lights/set',
    'home/frontdoor/visitor',
    'home/frontdoor/alarm'
];
return topics.map(function(t) {
    return { topic: t, payload: '', retain: true };
});

flow.set('govee_snapshot', {});
var devs = flow.get('govee_devices') || {};
if (!Object.keys(devs).length) { node.warn('Run discovery first'); return null; }
var msgs = Object.values(devs).map(function(d) {
    return { payload: JSON.stringify({msg:{cmd:'devStatus',data:{}}}), ip: d.ip, port: 4003 };
});
return [msgs];

try {
    var presets = JSON.parse(msg.payload);
    flow.set('govee_presets', presets);
    node.status({fill:'green', shape:'dot', text: Object.keys(presets).length + ' presets loaded'});
} catch(e) {
    node.status({fill:'yellow', shape:'ring', text: 'no presets file yet'});
}
return null;

var name    = msg.payload;
var devs    = flow.get('govee_devices') || {};
var nameMap = flow.get('govee_names')   || {};
if (!Object.keys(devs).length) { node.warn('Run discovery first'); return null; }

if (name === 'All Off') {
    flow.set('govee_current', {onOff:0, brightness:0, colortemp:4000, color:{r:0,g:0,b:0}, mode:'white'});
    var msgs = Object.values(devs).map(function(d) {
        return {payload:JSON.stringify({msg:{cmd:'turn',data:{value:0}}}), ip:d.ip, port:4003};
    });
    return [msgs, null];
}

var presets = flow.get('govee_presets') || {};
var preset  = presets[name];
if (!preset) { node.warn('Preset not found: ' + name); return null; }
flow.set('govee_current', preset);

var msgs = [];
Object.values(devs).forEach(function(d) {
    msgs.push({payload:JSON.stringify({msg:{cmd:'turn',      data:{value:preset.onOff}}}), ip:d.ip, port:4003});
    msgs.push({payload:JSON.stringify({msg:{cmd:'brightness', data:{value:preset.brightness}}}), ip:d.ip, port:4003});
    var colorData = preset.mode === 'color'
        ? {color: preset.color, colorTemInKelvin: 0}
        : {color: {r:0,g:0,b:0}, colorTemInKelvin: preset.colortemp || 4000};
    msgs.push({payload:JSON.stringify({msg:{cmd:'colorwc', data:colorData}}), ip:d.ip, port:4003});
});
return [msgs, {payload: preset}];

var name    = msg.payload;
var current = flow.get('govee_current') || {};
if (!Object.keys(current).length) { node.warn('Apply a preset first to initialise state'); return null; }
var presets = flow.get('govee_presets') || {};
presets[name] = JSON.parse(JSON.stringify(current));
flow.set('govee_presets', presets);
node.status({fill:'green', shape:'dot', text: name + ' saved'});
msg.payload = JSON.stringify(presets, null, 2);
return msg;

var current = flow.get('govee_current') || {};
current.brightness = msg.payload;
flow.set('govee_current', current);
var devs = flow.get('govee_devices') || {};
var msgs = Object.values(devs).map(function(d) {
    return {payload:JSON.stringify({msg:{cmd:'brightness',data:{value:msg.payload}}}), ip:d.ip, port:4003};
});
return [msgs];

node.warn('SRC:colortemp-slider value=' + msg.payload);
var current = flow.get('govee_current') || {};
current.colortemp = msg.payload;
current.mode = 'white';
flow.set('govee_current', current);
var devs = flow.get('govee_devices') || {};
var msgs = Object.values(devs).map(function(d) {
    return {payload:JSON.stringify({msg:{cmd:'colorwc',data:{color:{r:0,g:0,b:0},colorTemInKelvin:msg.payload}}}), ip:d.ip, port:4003};
});
return [msgs];

node.warn('SRC:color-cmd payload=' + JSON.stringify(msg.payload));
var current = flow.get('govee_current') || {};
if (msg.payload.mode === 'color') {
    current.color = {r:msg.payload.r, g:msg.payload.g, b:msg.payload.b};
    current.mode  = 'color';
} else {
    current.mode     = 'white';
    current.colortemp = current.colortemp || 4000;
}
flow.set('govee_current', current);
var devs = flow.get('govee_devices') || {};
var data = current.mode === 'color'
    ? {color: current.color, colorTemInKelvin: 0}
    : {color: {r:0,g:0,b:0}, colorTemInKelvin: current.colortemp};
var msgs = Object.values(devs).map(function(d) {
    return {payload:JSON.stringify({msg:{cmd:'colorwc',data:data}}), ip:d.ip, port:4003};
});
return [msgs];

var p = msg.payload;
if (!p) return null;
var brightness = p.brightness !== undefined ? p.brightness : 50;
var colortemp  = p.colortemp  || 4000;
return [
    {payload: brightness},
    {payload: colortemp},
    {payload: {color: p.color || {r:255,g:136,b:0}}}
];
